namespace CheckoutWizard.Models;

public class ShippingInfo
{
    public string Name { get; set; } = "";
    public string Address { get; set; } = "";
    public string City { get; set; } = "";
    public string ZipCode { get; set; } = "";
}

public class PaymentInfo
{
    public string CardNumber { get; set; } = "";
    public string ExpiryDate { get; set; } = "";
}

public class Order
{
    public ShippingInfo Shipping { get; set; } = new();
    public PaymentInfo Payment { get; set; } = new();
}

@using CheckoutWizard.Models

<div class="checkout-wizard">
    @if (_step == 1)
    {
        <ShippingStep Shipping="_order.Shipping"
                      OnNext="HandleShippingNext" />
    }
    else
    {
        <PaymentStep Payment="_order.Payment"
                     OnBack="HandleBack"
                     OnPlaceOrder="HandlePlaceOrder" />
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private Order _order = new();
    private int _step = 1;

    private void HandleShippingNext(ShippingInfo shipping)
    {
        _order.Shipping = shipping;
        _step = 2;
    }

    private void HandleBack()
    {
        _step = 1;
    }

    private async Task HandlePlaceOrder(PaymentInfo payment)
    {
        _order.Payment = payment;
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

@using CheckoutWizard.Models

<div class="shipping-step">
    <h3>Shipping Information</h3>

    <label>
        Name
        <input type="text" value="@_name" @onchange="e => _name = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        Address
        <input type="text" value="@_address" @onchange="e => _address = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        City
        <input type="text" value="@_city" @onchange="e => _city = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        Zip Code
        <input type="text" value="@_zipCode" @onchange="e => _zipCode = e.Value?.ToString() ?? string.Empty" />
    </label>

    @if (_validationError is not null)
    {
        <p class="validation-error">@_validationError</p>
    }

    <button @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<ShippingInfo> OnNext { get; set; }

    private string _name = "";
    private string _address = "";
    private string _city = "";
    private string _zipCode = "";
    private string? _validationError;

    protected override void OnParametersSet()
    {
        _name = Shipping.Name;
        _address = Shipping.Address;
        _city = Shipping.City;
        _zipCode = Shipping.ZipCode;
    }

    private async Task HandleNext()
    {
        if (string.IsNullOrWhiteSpace(_name) || string.IsNullOrWhiteSpace(_address))
        {
            _validationError = "Name and Address are required.";
            return;
        }

        _validationError = null;

        var shipping = new ShippingInfo
        {
            Name = _name,
            Address = _address,
            City = _city,
            ZipCode = _zipCode
        };

        await OnNext.InvokeAsync(shipping);
    }
}

@using CheckoutWizard.Models

<div class="payment-step">
    <h3>Payment Information</h3>

    <label>
        Card Number
        <input type="text" value="@_cardNumber" @onchange="e => _cardNumber = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        Expiry Date
        <input type="text" value="@_expiryDate" @onchange="e => _expiryDate = e.Value?.ToString() ?? string.Empty" />
    </label>

    <div class="payment-actions">
        <button @onclick="HandleBack">Back</button>
        <button @onclick="HandlePlaceOrder">Place Order</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public PaymentInfo Payment { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<PaymentInfo> OnPlaceOrder { get; set; }

    private string _cardNumber = "";
    private string _expiryDate = "";

    protected override void OnParametersSet()
    {
        _cardNumber = Payment.CardNumber;
        _expiryDate = Payment.ExpiryDate;
    }

    private async Task HandleBack()
    {
        await OnBack.InvokeAsync();
    }

    private async Task HandlePlaceOrder()
    {
        var payment = new PaymentInfo
        {
            CardNumber = _cardNumber,
            ExpiryDate = _expiryDate
        };

        await OnPlaceOrder.InvokeAsync(payment);
    }
}

