@using CheckoutWizard.Models

<div class="shipping-step">
    <h3>Shipping Information</h3>

    <label>
        Name
        <input type="text" value="@_name" @onchange="e => _name = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        Address
        <input type="text" value="@_address" @onchange="e => _address = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        City
        <input type="text" value="@_city" @onchange="e => _city = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        Zip Code
        <input type="text" value="@_zipCode" @onchange="e => _zipCode = e.Value?.ToString() ?? string.Empty" />
    </label>

    @if (_validationError is not null)
    {
        <p class="validation-error">@_validationError</p>
    }

    <button @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<ShippingInfo> OnNext { get; set; }

    private string _name = "";
    private string _address = "";
    private string _city = "";
    private string _zipCode = "";
    private string? _validationError;

    protected override void OnParametersSet()
    {
        _name = Shipping.Name;
        _address = Shipping.Address;
        _city = Shipping.City;
        _zipCode = Shipping.ZipCode;
    }

    private async Task HandleNext()
    {
        if (string.IsNullOrWhiteSpace(_name) || string.IsNullOrWhiteSpace(_address))
        {
            _validationError = "Name and Address are required.";
            return;
        }

        _validationError = null;

        var shipping = new ShippingInfo
        {
            Name = _name,
            Address = _address,
            City = _city,
            ZipCode = _zipCode
        };

        await OnNext.InvokeAsync(shipping);
    }
}

